var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"반갑소, 교우 여러분. 본인은 금일부로 아카데미에 입학하게 된 시엘이라 하오.","JPN":"初めまして、学友のみなさん。自分は今日をもってアカデミーに入学することになった、シエルと申します。","ENG":"Pleased to make your acquaintance, fellow students. I am Ciel and I shall be attending this Academy starting today.","TWN":"各位同學好，在下名叫希爾，今天剛入學。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"멍-! 헥헥!","JPN":"ワンッ！　ヘッヘッ！","ENG":"Woof! *Pant!* *Pant!*","TWN":"汪-！汪汪！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_07"},{"id":"L5_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"음.","JPN":"うむ。","ENG":"Mm.","TWN":"嗯。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"교우는 손이 참으로 복실복실하구려.","JPN":"学友の手はとてもモコモコとしていますね。","ENG":"You, fellow student, have very soft and fluffy hands.","TWN":"同學的手毛茸茸的。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"저기, 시엘 양…? 거긴 교실이 아니라 동물을 키우는 동아리부실인데…","JPN":"あの、シエルさん……？　そこは教室じゃなくて、動物を飼ってる部室なんだけど……","ENG":"Um, Ciel...? This is a club room where we raise animals, not a classroom...","TWN":"那個，希爾同學…？教室不在那裡，那裡是動物社團室。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그리고 그 강아지 친구는 종종 우리 학교에 놀러 오는 알렉산더라고 해.","JPN":"それに、そのワンちゃんはアレクサンダーっていう名前で、よくこの学校に遊びに来るの。","ENG":"And that puppy is Alexander. He comes by our school every now and then.","TWN":"那隻狗狗叫亞歷山大，牠常常來我們學校玩。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"멍-!","JPN":"ワンッ！","ENG":"Woof!","TWN":"汪-！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_08"},{"id":"L12_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"실례했구려. 본인은 밝은 곳에서 눈앞의 것을 잘 구분하지 못한다네.","JPN":"これは失礼しました。自分は明るいところでは目の前のものをちゃんと区別できませんので。","ENG":"Pardon me. I cannot distinguish figures in bright environments.","TWN":"失禮了，在下在明亮的地方無法分辨眼前的東西。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"혀로 핥으며 인사하는 털이 복슬복슬한 학생인 줄 알았소.","JPN":"舌で舐めながら挨拶する、毛むくじゃらな生徒かと。","ENG":"I assumed it was a fluffy classmate who greeted others with their tongue.","TWN":"在下還以為是一位毛茸茸的同學，用舔手的方式跟在下打招呼。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"눈앞의 상대가 사람인지 동물인지 구분 못할 정도면… 안경을 맞추는 편이 낫지 않을까?","JPN":"目の前の相手が人なのか動物なのかも区別できないなら……メガネをかけた方がいいんじゃない？","ENG":"If you can't tell a dog from a person... don't you think you need glasses?","TWN":"如果你連對方是人是狗都分不出來…那是不是該配個眼鏡？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"괜찮다오. 그런 깨지기 쉬운 도구에 의존하지 않도록 오랫동안 감각을 수련했으니.","JPN":"大丈夫です。そのような割れやすい道具に頼らないように、長らく感覚を修練してきましたので。","ENG":"No need. I have trained my senses so that I do not have to rely on such fragile utilities.","TWN":"不礙事，為了不倚賴那種易碎物，在下一直都有進行感覺訓練。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"눈을 감고도 날아오는 탄환 정도는 잡을 수 있소.","JPN":"目をつむっていても、飛んでくる弾丸くらいなら掴めます。","ENG":"For instance, I can catch a bullet with my eyes closed.","TWN":"已經練到就算閉著眼睛也能夠接住子彈。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"하하… 아무리 카운터라도 그건 힘들 것 같은데, 시엘 양은 대단하네.","JPN":"ハハ……シエルさんはすごいね、いくらカウンターでもそれは難しいと思うわ。","ENG":"Haha... That's amazing, Ciel. I think that's difficult even for a Counter.","TWN":"哈哈…這連一般的制裁者都很難做到呢，希爾同學好厲害。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 아카데미 시설은 대략 이 정도야. 어때? 학교 치곤 제법 넓고 복잡하지?","JPN":"はい、アカデミーの施設は大体こんな感じかな。どう？　学校のわりには結構広くて複雑でしょ？","ENG":"Okay, so that's a brief tour of the Academy. It's pretty big and complex for a school, right?","TWN":"學校差不多就這樣，怎麼樣？我們學校蠻大的，而且又很複雜對吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"길안내 고맙소. 정보습득에 많은 도움이 되었다오.","JPN":"道案内、ありがとうございます。情報を得るのに大変役立ちました。","ENG":"Thank you for the tour. You have greatly helped me obtain information.","TWN":"謝謝你帶在下參觀校園，對於認識這間學校很有幫助。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에이, 뭘~","JPN":"いやいや、そんな～","ENG":"Don't mention it!","TWN":"哎呀，幹嘛這麼客氣～"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아카데미의 강자들이 주로 출몰하는 구역 TOP5나 카메라에 걸리지 않는 사각지대 말고도 궁금한 게 있으면 얼마든지 불러줘! 가르쳐줄 테니까!","JPN":"アカデミーの強者がよく現われる区域のTOP5とか、カメラにバレない死角地帯の他にも気になることがあったらいつでも呼んでね！　教えてあげるから！","ENG":"If there's anything else you'd like to know, like where the top 5 strongest students at the Academy usually hang out, or the blind spots where the security cameras can't see you, just come and ask! I'd be happy to help!","TWN":"除了學院高手TOP5經常出沒的地方，或是不會被監視器拍到的死角之外，還想知道什麼儘管問我，我知無不答！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아! 그리고 난 미카라고 불러주면 돼!","JPN":"あ！　それから、あたしのことはミカって呼んで！","ENG":"Oh! My name's Mika, by the way!","TWN":"然後！你叫我米卡就好！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"흑동의 암살자는 모두의 이름을 기억하되 그 누구의 이름도 부르지 않는다.","JPN":"黒東の暗殺者はすべての名を覚えたとしても、その名を呼ばない。","ENG":"Black East members remember everyone's names, but we do not call anyone by them.","TWN":"黑東的刺客要記住每個人的名字，但不能提及任何人的名字。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"이름이 가진 온기에 냉정이 식는 순간 망설임이 생기고… 망설임을 가진 암살자는 쓸모가 없어질 테니 말이다.","JPN":"名が持つ温かさに冷静さがぬるくなる瞬間、迷いが生じ……迷いのある暗殺者は使い物にならなくなるからな。","ENG":"Names have warmth that creates hesitation... And an assassin with hesitation is useless.","TWN":"因為當你叫對方名字的瞬間，就會打破雙方的隔閡，於是會產生猶豫…猶豫不決的刺客等於是廢人。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"미안하구려. 아직 누군가를 이름으로는 부르는 건 익숙하지 않다오.","JPN":"申し訳ありません。まだ誰かを名前で呼ぶことには慣れていません。","ENG":"I apologize. I am not yet familiar with calling someone by their names.","TWN":"抱歉，在下還不習慣喊別人的名字。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아앗… 그래? 아쉽다.","JPN":"ああっ……そう？　それは残念。","ENG":"Oh... Really? That's a bummer.","TWN":"是喔…真可惜。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"시엘은 예쁘니까, 교우 같은 딱딱한 표현보단 이름으로 불러주면 다른 애들하고도 금방 친해질 수 있을 것 같은데!","JPN":"シエルちゃんは美人だから、学友とか堅苦しい表現より名前で呼んでくれると他のみんなともすぐ仲良くなれそうなのに。","ENG":"But you're so pretty! If you call others by their names, I'm sure you'll make friends in no time!","TWN":"希爾你長得這麼漂亮，要是可以不要用同學這種生疏的稱呼，而是直接叫名字的話，一定很快就能夠交到很多好朋友的。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"노력은 해보겠지만… 너무 기대는 마시오.","JPN":"努力はしてみますが……あまり期待しないでください。","ENG":"I will try... But do not expect too much.","TWN":"在下會努力嘗試看看…請不要抱太大的期待。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"헤헤, 괜찮아. 부담스러우면 억지로 맞추려 하지 않아도 돼.","JPN":"へへ、大丈夫だよ。気が向かないなら、無理して合わせなくても平気だから。","ENG":"Hehe, it's okay. You don't have to if you feel uncomfortable.","TWN":"嘿嘿，沒問題，你覺得有壓力的話，不用勉強自己配合。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앗, 벌써 시간이 이렇게 됐나? 곧 학생회 소집이네.","JPN":"あっ、もうこんな時間だね。もうすぐ生徒会の会議が始まるか。","ENG":"Oh, look at the time! It's almost time for the Student Council meeting.","TWN":"喔，時間過得真快？！快到學生會開會時間了。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"학생회…","JPN":"生徒会……","ENG":"Student Council...","TWN":"學生會…"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"거기엔 유능한 강자가 많이 있는 거요?","JPN":"そこには有能な強者がたくさんいるのですか？","ENG":"Does that place have competent and strong opponents?","TWN":"那裡有很多高手嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"엣헴- 그걸 그렇다고 말한다면 자화자찬 같달까… 일단 나도 임원이라서 말이야.","JPN":"えっへん！　そうだと言ったら、自画自賛になっちゃうけど……一応、あたしも生徒会の役員だからね。","ENG":"Ahem-  I guess so, but I don't like to brag about myself... because I'm also a member.","TWN":"嘿嘿，這樣說好像有點老王賣瓜的感覺，畢竟我也是學生會的幹部之一。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인도 함께 동행해도 괜찮겠소?","JPN":"自分が同行してもよろしいでしょうか。","ENG":"May I accompany you?","TWN":"在下也可以一同前往嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 딱히 안될 건 없지만, 왜?","JPN":"うん？　別にダメってわけじゃないけど、なんで？","ENG":"Hmm? I don't see why not, but why?","TWN":"嗯？可以是可以，但為什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어쩌면, 그곳에서 본인이 원하는 상대를 만날 수 있을 지도 모른다오.","JPN":"もしかすると、そこで自分の望む相手に出会えるかもしれません。","ENG":"Perhaps I will find the person I am searching for there.","TWN":"或許在那裡會遇到在下想找的人。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아하! 시엘 양은 아카데미에서 어느 정도 권위가 있는 친구를 사귀고 싶은 거구나?","JPN":"そっか！　シエルちゃんはアカデミーで、権力を持ってる友だちが欲しいんだね？","ENG":"Aha! You want to make friends with some authority figures in the academy, don't you?","TWN":"原來是這樣！你想在學院裡交到一些有權力地位的朋友嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 이유라면 얼마든지 환영이야!","JPN":"そういうことなら、いくらでも歓迎だよ！","ENG":"If that's it, you're more than welcome to!","TWN":"那隨時歡迎喔！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"특히 학생회장이 무척 반가워할 걸? 평소엔 학생회실을 찾아오는 학생은 드물거든!","JPN":"特に生徒会長がめっちゃ喜ぶと思う！　普段は生徒会室に遊びにくる生徒が少ないからね！","ENG":"I'm sure the Student President will be pleased to meet you! Not a lot of people visit the Student Council office, you know!","TWN":"學生會長一定會非常高興吧？因為學生都不太來學生會辦公室的。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야? 누가 학생회 얘길 꺼내나 했더니, 새로 왔다는 신입생이잖아?","JPN":"あら？　誰かが生徒会の話をしていると思ったら、新しく来た新入生じゃない。","ENG":"Huh? I was wondering who was talking about the Student Council. Isn't that the new kid?","TWN":"什麼嘛？我還以為是誰在說學生會的事？原來是新來的喔？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘? 지금 교양수업시간인데 여기서 뭐하는 거야?","JPN":"ナイエル？　今は教養の授業中なのに、ここで何してるの？","ENG":"Naielle? What are you doing here? Don't you have class?","TWN":"奈爾？現在是通識課時間，你在這裡做什麼？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 내가 뭐하러 그런 별볼일 없는 수업을 듣겠어? 그런 소양 따위 없어도 나 같은 인재를 모셔갈 곳이 널리고 널렸는데.","JPN":"ふん、私があんなくだらない授業を受けるわけないじゃない？　そんな素養がなくても、私みたいな人材を求めてるところはたくさんあるのよ。","ENG":"Hmph! Why would I sit through a boring class? I don't need class when there are plenty of organizations that recognize my class.","TWN":"哼，我幹嘛上那種無聊的課？就算不上那種課，還是很多地方爭相要我這種人才好嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼 안되지. 그래도 학생이라면 수업을 제대로 들어야…","JPN":"そんなのダメよ。生徒ならちゃんと授業を受けないと……","ENG":"That's nonsense. You should still attend classes if you're a student...","TWN":"這怎麼可以，身為一名學生，就是要乖乖上…"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그나저나 너!","JPN":"それより、あんた！","ENG":"And you!","TWN":"喂，我說你！"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대는…?","JPN":"貴殿は……？","ENG":"You are...?","TWN":"你是…？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이제 막 입학한 녀석이 어딜 주제넘게 학생회에 관심을 갖는 거야?","JPN":"入学したばかりのやつが、生徒会に興味があるなんて調子にのってるんじゃない？","ENG":"How dare you set your eyes on the Student Council when you just got here!","TWN":"剛入學的新生憑什麼對學生會有興趣？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"미리 말해두지만, 학생회의 임원 자리는 예전부터 이 엘리트님이 점찍어뒀으니…","JPN":"言っておくけど、生徒会の役員の座はこのエリート様が狙ってるんだから……","ENG":"Just so you know, the next available seat in the Student Council has long since been mine. The elite Naiell–","TWN":"我先聲明，我這個菁英早就已經鎖定學生會幹部的位置…"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"히익?! 다짜고짜 공격?!","JPN":"ひいっ！？　いきなり攻撃！？","ENG":"Eeep...! What was that for?!","TWN":"唔唔？！現在是要先打再說？！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…시엘?! 무슨 짓이야?!","JPN":"……シエルちゃん！？　急に何してるの！？","ENG":"...Ciel?! What are you doing?!","TWN":"…希爾？！你這是在做什麼？！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>안하무인에 넘치는 기백…</color>","JPN":"<color=#ffd34c>傍若無人、あふれる気迫……</color>","ENG":"<color=#ffd34c>Spirit brimming with confidence...</color>","TWN":"<color=#ffd34c>目中無人的氣魄…</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>기습에 제대로 반응한 걸 보면 실력은 허세가 아니지만, 동세가 엉망이군.</color>","JPN":"<color=#ffd34c>奇襲にきちんと反応したところを見るに実力は出まかせではないが、動きはめちゃくちゃだ。</color>","ENG":"<color=#ffd34c>Her response to my attack shows that she is not overstating her abilities, though her movement is a mess.</color>","TWN":"<color=#ffd34c>她能夠及時做出反應，看來不是在吹噓自己的能力，但人品好像有點問題。</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>백서의 도전자이길 기대했건만, 착각이었나.</color>","JPN":"<color=#ffd34c>白西の挑戦者であることを期待したが、勘違いだったか。</color>","ENG":"<color=#ffd34c>I was hoping she would be one of White West's challengers, but I was mistaken.</color>","TWN":"<color=#ffd34c>原本還期待她是白西的挑戰者，結果是一場誤會嗎？</color>"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"미안하오. 본인은 화장실이 급하면 과격해지는 편이라서.","JPN":"申し訳ありません。自分はトイレに行きたくなると、気性が荒くなるのです。","ENG":"My apologies. I have a tendency to become violent whenever I need to go to the bathroom.","TWN":"抱歉，在下內急時動作會比較激烈。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"길을 비켜주지 않겠소?","JPN":"道を開けてもらえませんか。","ENG":"Could you step out of my way, please?","TWN":"麻煩讓一下？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그… 그래? 그 정도로 급하면 진작 말하지 그랬어.","JPN":"そ……そう？　そんなに行きたかったなら、早く言えばいいじゃない。","ENG":"O-oh yeah? You should've said something if you really needed to go that bad.","TWN":"是…是喔？尿急喔，早說嘛。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"고맙구려.","JPN":"ありがとうございます。","ENG":"I thank you.","TWN":"多謝。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 나중에 다시 찾겠소, 학생회 임원님.","JPN":"それでは、また後ほど。生徒会の役員殿。","ENG":"Then, I shall visit later, member of the Student Council.","TWN":"下次見，學生會幹部。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어… 응.","JPN":"え……うん。","ENG":"Oh... okay.","TWN":"喔…好。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐, 뭐야! 저 녀석! 고작 그딴 이유로 사람을 공격해?! 완전 사이코패스잖아!","JPN":"な、何なのよ！　あいつ！　そんな理由で人を攻撃するなんて！　サイコパスじゃない！","ENG":"W-what's her deal?! Attacking someone for a reason like that! She's a psychopath!","TWN":"搞，搞什麼！那傢伙因為尿急就攻擊人？根本是神經病吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"다짜고짜 시비를 거는 네가 할 말은 아니지 않아?","JPN":"出会い頭に文句をつけたあなたが言うことじゃないんじゃない。","ENG":"Says the person who went up to stir up a fight with her.","TWN":"誰叫你沒事找人家麻煩？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"계속 그런 식으로 행동하면 학창시절 내내 친구 사귀긴 힘들 걸?","JPN":"いつもそんなだと、学校でずっと友だちできないよ？","ENG":"Keep that up if you don't want to make any friends.","TWN":"你老是這樣的話，我看在你求學階段要交到朋友可能會很困難。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 상관없어. 나한테 맞추지 못하는 녀석은 나도 필요 없거든?","JPN":"ふん、構わないわ。私に合わせられないやつなんて、私だってゴメンだから。","ENG":"Hmph! Like I care! I don't need anyone who can't cater to my needs!","TWN":"哼，不希罕，我也不想跟合不來的人做朋友！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"두고 보라고. 신입생 주제에 나한테 덤빈 걸 몇 번이고 후회하게 해주지.","JPN":"見てなさいよ。新入生のくせに、私に歯向かったことを何度も後悔させてあげる。","ENG":"Just you watch. I'll make the new kid regret her decision to attack me.","TWN":"走著瞧，新生還敢來惹我，我會讓她後悔莫及！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…그런 일이 있었어요.","JPN":"……そんなことがありました。","ENG":"...That's what happened.","TWN":"…事情就是這樣。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"흠, 그렇군요.","JPN":"ふーん、そうですか。","ENG":"Hmm, I see.","TWN":"嗯，我知道了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"화장실이 급하다고 나이엘에게 덤비다니 제법 용감한 신입생이네요.","JPN":"トイレに行きたいからとナイエルに歯向かうとは、なかなか勇敢な新入生ですね。","ENG":"The transfer student is quite brave for attacking Naielle solely because she needed to use the restroom.","TWN":"因為內急就攻擊奈爾，看來是位勇氣十足的新生呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘이 복수하려고 벼르는 것 같던데, 미리 두 사람을 떨어트려 두는 편이 좋지 않을까요?","JPN":"ナイエルは復讐する気満々のようで、今から二人を離しておいた方がいいんじゃないですか？","ENG":"I think Naielle is bent on revenge. Don't you think it'll be better to separate them?","TWN":"奈爾似乎想找機會報仇，是不是暫時將她們二人分開比較好？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그 자존심 강한 바보를 내버려뒀다간 분명 사고를 칠 게 틀림없다고요!","JPN":"あのプライドが高いバカを放っておいたら、きっと何かしでかすに違いないです！","ENG":"I'm sure she'll do something if we leave that stubborn idiot alone!","TWN":"那個傻瓜自尊心那麼強，不管她的話一定會惹事！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"너무 걱정 말아요. 선을 넘을 조짐이 보인다면 제가 중재할 테니.","JPN":"そんなに心配しないでください。行き過ぎるようでしたら、私が仲裁しますから。","ENG":"There is nothing to worry about. If I think that she is crossing the line, I will intervene.","TWN":"放心，要是她有越界的跡象，到時我會居中協調的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그럼, 다음 안건은… 아카데미 기물파손과 외부 재산손괴에 대한 책임 건이야.","JPN":"じゃあ、次の案件は……アカデミーの器物破損と外部の財産損壊の責任に関する件だねぇ。","ENG":"So, the next item on the agenda is... the issue of external and Academy property damage liability.","TWN":"那下一個議題是…關於傷害賠償和損壞他人財產的責任問題。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"중등부의 애니가 빌딩에 락카칠을 하다가 걸려서 배상요청이 들어왔어.","JPN":"中等部のアニーが建物にスプレーで落書きしたのが見つかって、賠償請求が来てるよ。","ENG":"Annie from middle school was caught painting a building with spray paint. Because of that, they are demanding reimbursement from us.","TWN":"國中部的安妮在大樓外塗鴉被抓到，對方向學院要求賠償。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"고등부의 어그로와 블로킹은 불량배들과 다투다가 폭행으로 연행됐고.","JPN":"高等部のアグロとブロッキングは、不良たちとケンカして警官に連行されたし。","ENG":"Aggro and Block from high school got into a fight with some bullies and got arrested.","TWN":"高中部的阿格洛、布洛京和小混混發生爭執，因為暴力事件而遭到逮捕。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"연행…?! 그 녀석들 지금 어딨는데요?","JPN":"連行……！？　あいつら、今どこにいるんですか？","ENG":"Arrested...?! Where are they now?","TWN":"逮捕…？！那學生現在在哪裡？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"애니는 정당한 예술활동이었다며 자택에서 시위 중, 어그로와 블로킹은 경찰서에 있어.","JPN":"アニーは正当な芸術活動だったとして自宅謹慎中、アグロとブロッキングは警察署にいるねぇ。","ENG":"Annie is at home, protesting that it was a part of her artistic expression, and Aggro and Block are at the police station.","TWN":"安妮聲稱塗鴉是合法的藝術行為，現在關在家中表達不滿，阿格洛和布洛京在警察局。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"경찰서? 그런데 우리 여기서 이러고 있어도 괜찮은 건가요?!","JPN":"警察署？　そんな状況で、あたしたちはここにいても大丈夫なんですか！？","ENG":"The police station? Are you sure we shouldn't go down there right now?!","TWN":"警察局？那我們不需要去一趟嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC"},{"id":"L8_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"하암- 진정해.","JPN":"ふああ～落ち着いて。","ENG":"*Yawn* Settle down.","TWN":"哈啊～冷靜點。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"미카 스타의 장점은… 언제 어디서나 미소를 잃지 않는 긍정적인 마인드라고.","JPN":"ミカ★スターの長所は……いつ、どこにいても笑顔を忘れないポジティブなマインドだから。","ENG":"Your strength, Mika, is that you always put on a smile and think positively.","TWN":"米卡★斯塔的優點…就是隨時隨地都能夠保持微笑的正能量。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미소는 뭔 미소! 우리 학생이 경찰한테 붙잡혔다는데 어떻게 긍정적일 수 있어요!","JPN":"笑顔どころじゃないですよ！　うちの生徒が警察に捕まってるのに、どうやってポジティブでいられるんですか！","ENG":"Smile?! Are you kidding me?! Our students are being held in a police station and you want me to have a positive mind?!","TWN":"現在誰還笑得出來！我們的學生被警察抓欸，哪來什麼正能量！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…네, 잘 알겠습니다.","JPN":"……はい、かしこまりました。","ENG":"...Okay, understood.","TWN":"…好，我明白了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장님…? 방금 누구랑 통화한 거예요?","JPN":"生徒会長……？　今誰と電話してたんですか？","ENG":"Ms. President...? Who were you talking to on the phone just now?","TWN":"學生會長…？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"건물주와의 협상을 통해 애니의 배상금 문제는 제가 방금 처리했습니다.","JPN":"建物のオーナーと交渉して、アニーの賠償金問題は私がいま解決しました。","ENG":"I talked with the owner of the building and resolved the issue regarding Annie's vandalism.","TWN":"我剛和屋主談完，賠償金的問題已經解決了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"경찰서의 두 사람도 크게 다친 사람이 없으니 훈방조치 후 풀려날 거라는 답변을 받았어요.","JPN":"警察署にいる二人も大怪我をした者はいないので、訓戒処分の後に解放されるとの返答をもらいました。","ENG":"For the two at the police station, I got a reply that they are not seriously injured and will be sent home after they are given a warning.","TWN":"警察局那邊也回覆說，因為大家傷勢都不嚴重，所以口頭懲戒完就會釋放他們。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"정말요?! 역시 학생회장님!","JPN":"本当ですか！？　さすが生徒会長！","ENG":"Really?! You're amazing as always, Ms. President!","TWN":"真的嗎？！不愧是學生會長！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"안심하기엔 일러… 최근 특정 학생들이 이런 문제를 일으키는 빈도가 늘고 있어.","JPN":"安心するにはまだ早いよ……最近、特定の生徒がこんな問題を起こす頻度が増えてる。","ENG":"Don't celebrate just yet... Recently, there has been an increasing amount of problems caused by certain students.","TWN":"還不能放心…最近某些特定的學生滋事的頻率似乎越來越高。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"대책을 세우지 못하면… 앞으로도 이런 일이 계속 생길 거야.","JPN":"対策がないと……これからもこんなことがまた起きるよ。","ENG":"If we don't set up any countermeasures... incidents like this will continue to occur.","TWN":"若是不能制定對策…這種事情之後只會繼續發生。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그렇긴 하네요.","JPN":"それもそうですね。","ENG":"You're right.","TWN":"說的也是。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미의 구성원 대부분은 자신의 의사와 상관없이 워치라는 큰 힘을 얻게 된 아직 미숙한 학생들입니다.","JPN":"アカデミーの構成員の多くが、自分の意志とは関係なくウォッチという大きな力を得ることになった、まだ未熟な生徒たちです。","ENG":"The majority of the Academy's members are inexperienced students who did not have a say in the acquisition of abilities through Watches.","TWN":"學院大部分的學生，都是在沒有自覺的狀況下獲得能量環這個強大力量的，因此還無法成熟地使用這股力量。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"자신의 길을 찾기 전까지는… 방황하는 것이 수순이죠.","JPN":"自分の進むべき道が見つかるまでは……気の迷いを犯すものです。","ENG":"It is natural to be confused... until they find their own path.","TWN":"在找到自己的路之前…徬徨是很正常的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"문제아들을 온종일 학교에 붙잡아 둘 수도 없고, 민폐라니까요. 정말-","JPN":"問題児を一日中学校に引き留めておくわけにもいかないし、迷惑なんですよね。まったく～","ENG":"And we can't just put every problematic kid in detention all day long. Ugh, such a hassle!","TWN":"又不能把問題學生整天留學察看，真是麻煩，討厭。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"경우에 따라선… 실효성이 입증된 교정 교육을 통해 얌전한 성격으로 만들 수는 있어.","JPN":"場合によっては……実効性が立証された矯正教育で大人しい性格にすることはできるよ。","ENG":"In some cases... we can tone their personalities down with an effective correctional education.","TWN":"可以視情況…透過證實有效的矯正教育，將他們導正為乖巧的學生。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그 교육… 합법은 맞는 건가요?","JPN":"その教育……合法なんですよね？","ENG":"I-is that education... legal?","TWN":"你所謂的教育…應該是合法的吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미는 모두의 개성을 존중해야 합니다. 성격을 교정하는 교육법은 채택할 수 없어요.","JPN":"アカデミーはみんなの個性を尊重すべきです。性格を矯正する教育法は採用できません。","ENG":"The Academy respects everyone's uniqueness. We cannot implement any education that goes against this principle.","TWN":"學院應該尊重每位學生的個性，不能採用性格矯正的教育方法。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래도… 진짜 진짜, 혹시라도, 만약에… 이러다 정말 큰 사고라도 터지면 그땐 어쩌죠?","JPN":"でも……本当に、もしかして、万が一……これでもっと大きな事故でも起きたら、その時はどうしますか？","ENG":"But still... what if, in a million-to-one chance... a huge accident happens?","TWN":"但是…萬一萬一…這樣下去真的出大事的話怎麼辦？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학교에 규칙이 있다고 해서 모든 학생들이 잠자코 따르지 않는다는 건… 다들 알잖아요.","JPN":"校則があっても、すべての生徒が大人しく従うわけではないってことは……みんな知ってるでしょ？","ENG":"Plus, we all know that just because there are rules at school... not everyone is going to follow them.","TWN":"學校的規定是一回事，但並不是所有學生都會乖乖遵守…這不是眾所皆知的嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇게 되기 전에, 다른 최선의 방법을 찾아야겠죠.","JPN":"そうなる前に、他の最善方法を探さないといけないでしょうね。","ENG":"We must find another solution before that happens.","TWN":"當然必須在最壞的情況發生前，趕緊找到其他對策。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생들이 엇나가고 방황하지 않도록 손을 잡아주는 것이, 우리 아카데미의 역할이니까요.","JPN":"生徒が横道にそれて自分を見失わないように手をとってあげることが、我々アカデミーの役割ですから。","ENG":"It is the Academy's duty to guide students down the right path.","TWN":"學院的責任，就是確保學生不走偏路，幫助他們找到正確的方向。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};